import React, { useEffect, useRef } from 'react';
import { Alert, Box, Button, Card, CardContent, Stack, Typography } from '@mui/material';
import CameraAltIcon from '@mui/icons-material/CameraAlt';
import RefreshIcon from '@mui/icons-material/Refresh';
import { StatusMessage } from '@/components/StatusMessage';
import { PublicProfileResult } from '@/types/profile.types';
import { Validator, CallStatus } from '@/types/api.types';
import { IdentityDisplay } from './IdentityDisplay';
import { BrowserMultiFormatReader } from '@zxing/library';
import { ProfileServices, ProfileServicesError } from '@/api';
import { initialStateData, StateData } from '@/store';
import { ApiComponentStateManager } from '@/lib/api-state';
import { logger } from '@/utils/logger';

export const IdentityVerifyScan: React.FC = () => {
    const [scannedProfile, setScannedProfile] = React.useState<StateData<PublicProfileResult>>(initialStateData<PublicProfileResult>());
    const [showScanner, setShowScanner] = React.useState<boolean>(true);
    const [errorMessage, setErrorMessage] = React.useState<string>("");

    const videoRef = useRef<HTMLVideoElement>(null);
    const codeReaderRef = useRef<BrowserMultiFormatReader | null>(null);

    const handleScan = (result: string | null) => {
        if (result && Validator.IsGuid(result)) {
            ApiComponentStateManager(ProfileServices.GetProfileById(result), setScannedProfile);
            setShowScanner(false);
            setErrorMessage("");
        } else {
            setScannedProfile(initialStateData<PublicProfileResult>());
        }
    };

    const handleReset = () => {
        logger.debug('IdentityVerifyScan', 'Resetting scanner');
        setScannedProfile(initialStateData<PublicProfileResult>());
        setShowScanner(true);
        setErrorMessage("");
    };

    useEffect(() => {
        if (!showScanner) return;

        const codeReader = new BrowserMultiFormatReader();
        codeReaderRef.current = codeReader;
        codeReader
            .listVideoInputDevices()
            .then((videoInputDevices) => {
                if (videoInputDevices.length > 0) {
                    const selectedDeviceId = videoInputDevices.find(device => device.label.toLowerCase().includes('back') || device.label.toLowerCase().includes('rear'))?.deviceId || videoInputDevices[0].deviceId;
                    codeReader.decodeFromVideoDevice(
                        selectedDeviceId,
                        videoRef.current,
                        (result) => {
                            if (result) {
                                handleScan(result.getText());
                                codeReader.reset();
                            }
                        }
                    );
                } else {
                    setErrorMessage('No camera detected on this device.');
                    logger.error('IdentityVerifyScan', 'No video input devices found');
                }
            })
            .catch((err) => {
                setErrorMessage('Could not access the camera. Please check permissions.');
                logger.error('IdentityVerifyScan', 'listVideoInputDevices failed', err);
            });

        return () => {
            codeReader.reset();
        };
    }, [showScanner]);

    return (
        <>
            {showScanner && (
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                        <Stack direction="row" spacing={1.25} sx={{ alignItems: 'center', mb: 1.5 }}>
                            <CameraAltIcon color="primary" />
                            <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                                Live camera scan
                            </Typography>
                        </Stack>
                        <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mb: 1.5 }}>
                            Hold the alumni's QR badge within the camera view. Detection happens automatically.
                        </Typography>
                        <Box
                            sx={{
                                position: 'relative',
                                bgcolor: '#000',
                                borderRadius: 1.5,
                                overflow: 'hidden',
                                aspectRatio: '4 / 3',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                            }}
                        >
                            <video
                                ref={videoRef}
                                style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                muted
                                playsInline
                            />
                        </Box>
                        {errorMessage && (
                            <Alert severity="error" sx={{ mt: 2 }}>{errorMessage}</Alert>
                        )}
                    </CardContent>
                </Card>
            )}
            {scannedProfile.data.id && scannedProfile.status === CallStatus.Success && (
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                        <Box sx={{ display: 'flex', justifyContent: 'center', mb: 2 }}>
                            <IdentityDisplay {...scannedProfile.data} />
                        </Box>
                        <Box sx={{ display: 'flex', justifyContent: 'flex-end' }}>
                            <Button variant="contained" startIcon={<RefreshIcon />} onClick={handleReset}>
                                Scan another
                            </Button>
                        </Box>
                    </CardContent>
                </Card>
            )}
            {scannedProfile.status !== CallStatus.NotStarted && !scannedProfile.data.id && (
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                        <StatusMessage
                            notStartedMessage="Verifying scanned profile..."
                            failureMessage={ProfileServicesError.GetProfileByIdError(scannedProfile.httpStatus)}
                            currentStatus={scannedProfile.status}
                            correlationId={scannedProfile.correlationId}
                        />
                    </CardContent>
                </Card>
            )}
        </>
    );
};

