import React from 'react';
import { PageContainer } from '@/components/PageContainer';
import { Card, CardContent, Stack, ToggleButton, ToggleButtonGroup, Typography } from '@mui/material';
import QrCodeScannerIcon from '@mui/icons-material/QrCodeScanner';
import CameraAltIcon from '@mui/icons-material/CameraAlt';
import PhotoLibraryIcon from '@mui/icons-material/PhotoLibrary';
import { IdentityVerifyImage } from './IdentityVerifyImage';
import { IdentityVerifyScan } from './IdentityVerifyScan';

type Mode = 'scan' | 'image';

export const IdentityVerify: React.FC = () => {
    const [mode, setMode] = React.useState<Mode>('scan');

    const handleChange = (_: React.MouseEvent<HTMLElement>, value: Mode | null) => {
        if (value) setMode(value);
    };

    return (
        <PageContainer
            icon={<QrCodeScannerIcon color="primary" />}
            title="Verify alumni ID"
            subtitle="Use your camera to scan an alumni QR badge, or upload a saved screenshot."
        >
            <Card sx={{ mb: 2 }}>
                <CardContent>
                    <Stack spacing={1.25}>
                        <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 600 }}>
                            Verification mode
                        </Typography>
                        <ToggleButtonGroup
                            value={mode}
                            exclusive
                            onChange={handleChange}
                            color="primary"
                            size="small"
                            fullWidth
                            sx={{ '& .MuiToggleButton-root': { textTransform: 'none', fontWeight: 500 } }}
                        >
                            <ToggleButton value="scan">
                                <CameraAltIcon fontSize="small" sx={{ mr: 1 }} />
                                Scan with camera
                            </ToggleButton>
                            <ToggleButton value="image">
                                <PhotoLibraryIcon fontSize="small" sx={{ mr: 1 }} />
                                Upload screenshot
                            </ToggleButton>
                        </ToggleButtonGroup>
                    </Stack>
                </CardContent>
            </Card>
            {mode === 'scan' ? <IdentityVerifyScan /> : <IdentityVerifyImage />}
        </PageContainer>
    );
};
