import React from "react";
import { Alert, Box, Button, Card, CardContent, Chip, Stack, Typography } from "@mui/material";
import AddPhotoAlternateIcon from '@mui/icons-material/AddPhotoAlternate';
import CheckIcon from '@mui/icons-material/Check';
import RefreshIcon from '@mui/icons-material/Refresh';
import PhotoLibraryIcon from '@mui/icons-material/PhotoLibrary';
import { BrowserMultiFormatReader } from '@zxing/library';
import { Validator, CallStatus } from "@/types/api.types";
import { StatusMessage } from "@/components/StatusMessage";
import { PublicProfileResult } from "@/types/profile.types";
import { IdentityDisplay } from "./IdentityDisplay";
import { ProfileServices, ProfileServicesError } from "@/api";
import { initialStateData, StateData } from "@/store";
import { ApiComponentStateManager } from "@/lib/api-state";
import { logger } from '@/utils/logger';

export const IdentityVerifyImage = () => {
    const [displayName, setDisplayName] = React.useState<string>("");
    const [imageUrl, setImageUrl] = React.useState<string>("");
    const [errorMessage, setErrorMessage] = React.useState<string>("");
    const [showScanner, setShowScanner] = React.useState<boolean>(true);
    const [profileId, setProfileId] = React.useState<string>("");
    const [scannedProfile, setScannedProfile] = React.useState<StateData<PublicProfileResult>>(initialStateData<PublicProfileResult>());

    const decodeFromImageUrl = () => {
        if (!imageUrl) return;
        const codeReader = new BrowserMultiFormatReader();
        codeReader.decodeFromImageUrl(imageUrl)
            .then((result: { getText: () => string; }) => {
                setErrorMessage("");
                logger.debug('IdentityVerifyImage', 'decode result', result);
                const text = result.getText();
                if (text && Validator.IsGuid(text)) {
                    logger.debug('IdentityVerifyImage', 'decoded text', text);
                    setProfileId(text);
                } else {
                    setErrorMessage("Invalid QR code in the selected image.");
                }
            })
            .catch(() => {
                setErrorMessage("Couldn't detect a QR code. Try a clearer screenshot.");
            });
    };

    const handleVerify = () => {
        decodeFromImageUrl();
    };

    const handleImageChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        setErrorMessage("");
        const file = event.target.files?.[0];
        if (file) {
            const fileBase64 = URL.createObjectURL(file);
            setDisplayName(file.name);
            setImageUrl(fileBase64);
        }
    };

    const handleReset = () => {
        setErrorMessage("");
        setShowScanner(true);
        setDisplayName("");
        setImageUrl("");
        setProfileId("");
        setScannedProfile(initialStateData<PublicProfileResult>());
    };

    React.useEffect(() => {
        if (profileId && Validator.IsGuid(profileId)) {
            ApiComponentStateManager(ProfileServices.GetProfileById(profileId), setScannedProfile);
        }
    }, [profileId]);

    return (
        <>
            {showScanner && (
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                        <Stack direction="row" spacing={1.25} sx={{ alignItems: 'center', mb: 1.5 }}>
                            <PhotoLibraryIcon color="primary" />
                            <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                                Upload QR screenshot
                            </Typography>
                        </Stack>
                        <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mb: 1.5 }}>
                            Pick an image from your device that contains an alumni QR badge.
                        </Typography>

                        <input
                            accept="image/*"
                            hidden
                            multiple={false}
                            id="qr-button-file"
                            type="file"
                            onChange={handleImageChange}
                        />
                        <Stack direction={{ xs: 'column', sm: 'row' }} spacing={1.5} sx={{ alignItems: { sm: 'center' } }}>
                            <Button
                                component="label"
                                htmlFor="qr-button-file"
                                variant="outlined"
                                startIcon={<AddPhotoAlternateIcon />}
                                sx={{ textTransform: 'none' }}
                            >
                                Choose image
                            </Button>
                            {displayName && (
                                <Chip
                                    icon={<CheckIcon />}
                                    label={displayName}
                                    size="small"
                                    color="success"
                                    variant="outlined"
                                    sx={{ maxWidth: 320, '& .MuiChip-label': { overflow: 'hidden', textOverflow: 'ellipsis' } }}
                                />
                            )}
                            <Button
                                onClick={handleVerify}
                                variant="contained"
                                disabled={!imageUrl}
                                sx={{ textTransform: 'none', ml: { sm: 'auto' } }}
                            >
                                Verify
                            </Button>
                        </Stack>

                        {imageUrl && (
                            <Box sx={{ mt: 2, display: 'flex', justifyContent: 'center' }}>
                                <Box
                                    component="img"
                                    src={imageUrl}
                                    alt="Selected QR"
                                    sx={{ maxWidth: 220, maxHeight: 220, borderRadius: 1, border: '1px solid', borderColor: 'divider' }}
                                />
                            </Box>
                        )}

                        {errorMessage && (
                            <Alert severity="error" sx={{ mt: 2 }}>{errorMessage}</Alert>
                        )}
                    </CardContent>
                </Card>
            )}

            {scannedProfile.data.id && scannedProfile.status === CallStatus.Success && (
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                        <Box sx={{ display: 'flex', justifyContent: 'center', mb: 2 }}>
                            <IdentityDisplay {...scannedProfile.data} />
                        </Box>
                        <Box sx={{ display: 'flex', justifyContent: 'flex-end' }}>
                            <Button variant="contained" startIcon={<RefreshIcon />} onClick={handleReset}>
                                Verify another
                            </Button>
                        </Box>
                    </CardContent>
                </Card>
            )}

            {scannedProfile.status !== CallStatus.NotStarted && !scannedProfile.data.id && (
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                        <StatusMessage
                            notStartedMessage="Verifying profile..."
                            failureMessage={ProfileServicesError.GetProfileByIdError(scannedProfile.httpStatus)}
                            currentStatus={scannedProfile.status}
                            correlationId={scannedProfile.correlationId}
                        />
                    </CardContent>
                </Card>
            )}
        </>
    );
};

